# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request
from eth_account.messages import encode_defunct
from web3 import Web3, HTTPProvider

app = Flask(__name__)
web3 = Web3(HTTPProvider('http://localhost:8545')) #change with your infura url or Geth RPC server URL

@app.route('/verify', methods=['POST'])
def verify():
    data = request.get_json()
    if 'message' not in data or 'signature' not in data:
        return {'error': 'Invalid Request'}, 400
        
    message = encode_defunct(text=data['message'])
    
    try:
        account = web3.eth.account.recoverHash(message.hash, signature=data['signature'])
        if data['address'].lower() == account.lower():
            return {'verified': True}, 200
        else:
            return {'error': 'Signature does not match the provided address'}, 401
    except Exception as e:
        return {'error': str(e)}, 500
        
if __name__ == "__main__":
    app.run()